"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["68278"],{76506(a){a.exports=JSON.parse('{"tag":{"label":"funnel","permalink":"/sysanalyst-kb.github.io/docs/tags/funnel","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":2,"items":[{"id":"specialization/ecommerce-analytics","title":"E-commerce \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u0438 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432\u0430\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430","description":"E-commerce \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u0441\u0431\u043E\u0440, \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0438 \u0432\u0438\u0437\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F \u043C\u0435\u0442\u0440\u0438\u043A CDP (Customer Data Platform), \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432\u044B\u0435 \u0432\u043E\u0440\u043E\u043D\u043A\u0438 (funnel), \u043A\u043E\u0433\u043E\u0440\u0442\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0437 (cohort), ABC-XYZ \u0430\u043D\u0430\u043B\u0438\u0437 \u0430\u0441\u0441\u043E\u0440\u0442\u0438\u043C\u0435\u043D\u0442\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u0434\u0430\u0448\u0431\u043E\u0440\u0434\u044B \u0438 rules \u0434\u043B\u044F \u0430\u043B\u0435\u0440\u0442\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-analytics"},{"id":"specialization/gamedev-analytics","title":"Game Analytics","description":"Game Analytics \u2014 \u0444\u0443\u043D\u0434\u0430\u043C\u0435\u043D\u0442 \u0432\u0441\u0435\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0432 \u0438\u0433\u0440\u0430\u0445. \u0422\u0440\u0435\u043A\u0438\u043D\u0433 \u0441\u043E\u0431\u044B\u0442\u0438\u0439 (event tracking), \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435 \u0432\u043E\u0440\u043E\u043D\u043E\u043A (funnel), \u0430\u043D\u0430\u043B\u0438\u0437 \u043C\u0435\u0442\u0440\u0438\u043A (retention, ARPU, LTV) \u0438 A/B \u0442\u0435\u0441\u0442\u044B. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0445\u0435\u043C\u0443 \u0441\u043E\u0431\u044B\u0442\u0438\u0439, \u0434\u0430\u0448\u0431\u043E\u0440\u0434\u044B \u0438 \u043F\u0430\u0439\u043F\u043B\u0430\u0439\u043D \u0434\u0430\u043D\u043D\u044B\u0445 (\u043A\u043B\u0438\u0435\u043D\u0442 \u2192 \u0441\u0435\u0440\u0432\u0435\u0440 \u2192 DWH \u2192 BI). \u0411\u0435\u0437 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0438 \u0438\u0433\u0440\u044B \u0441\u043B\u0435\u043F\u044B: \u043D\u0435\u043B\u044C\u0437\u044F \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u0438\u0433\u0440\u043E\u043A\u0438 \u0443\u0445\u043E\u0434\u044F\u0442, \u0433\u0434\u0435 \u043E\u043D\u0438 \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u044E\u0442 \u0438 \u0447\u0442\u043E \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u0434\u0435\u043D\u044C\u0433\u0438. \u0412 GameDev \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u043D\u0435 \xab\u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0430\xbb, \u0430 \u0434\u0432\u0438\u0436\u0443\u0449\u0430\u044F \u0441\u0438\u043B\u0430 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-analytics"}],"unlisted":false}}')}}]);